INSERT INTO `course_question_bank` VALUES ('076e2008-4fd7-11f1-9abe-6c02e0d26821','dde5cde4-4fcc-11f1-9abe-6c02e0d26821',NULL,NULL,'454cde6d-4f80-11f1-ba5b-00090ffe0001','multiple_choice','In a route pattern \'/items/:itemId\', what does \':itemId\' represent?','[\"A static segment\", \"A query parameter\", \"A route parameter placeholder\", \"A middleware function\"]',2,'2026-05-14 23:53:58','2026-05-14 23:53:58'),('076e8932-4fd7-11f1-9abe-6c02e0d26821','dde5cde4-4fcc-11f1-9abe-6c02e0d26821',NULL,NULL,'454cde6d-4f80-11f1-ba5b-00090ffe0001','true_false','Middleware runs in the order it is registered on the app.','[\"True\", \"False\"]',0,'2026-05-14 23:53:58','2026-05-14 23:53:58'),('076fe183-4fd7-11f1-9abe-6c02e0d26821','dde5cde4-4fcc-11f1-9abe-6c02e0d26821',NULL,NULL,'454cde6d-4f80-11f1-ba5b-00090ffe0001','multiple_choice','Which HTTP method is typically used to update part of a resource?','[\"GET\", \"POST\", \"PATCH\", \"DELETE\"]',2,'2026-05-14 23:53:58','2026-05-14 23:53:58'),('07714cac-4fd7-11f1-9abe-6c02e0d26821','dde5cde4-4fcc-11f1-9abe-6c02e0d26821',NULL,NULL,'454cde6d-4f80-11f1-ba5b-00090ffe0001','multiple_choice','Which is a common place to centralize API error handling in Express?','[\"Inside each controller only\", \"An error-handling middleware (err, req, res, next)\", \"In the database layer\", \"In the client application\"]',1,'2026-05-14 23:53:58','2026-05-14 23:53:58'),('07727fac-4fd7-11f1-9abe-6c02e0d26821','dde5cde4-4fcc-11f1-9abe-6c02e0d26821',NULL,NULL,'454cde6d-4f80-11f1-ba5b-00090ffe0001','multiple_choice','In a simple model, which operation would you use to fetch a single document by its unique id?','[\"create()\", \"findById()\", \"delete()\", \"all()\"]',1,'2026-05-14 23:53:58','2026-05-14 23:53:58'),('0772f7fa-4fd7-11f1-9abe-6c02e0d26821','dde5cde4-4fcc-11f1-9abe-6c02e0d26821',NULL,NULL,'454cde6d-4f80-11f1-ba5b-00090ffe0001','true_false','Decoding a JWT payload guarantees the token is valid and not tampered with.','[\"True\", \"False\"]'