e0d26821','dde5cde4-4fcc-11f1-9abe-6c02e0d26821',NULL,NULL,'454cde6d-4f80-11f1-ba5b-00090ffe0001','true_false','Express is a minimal and flexible Node.js web application framework.','[\"True\", \"False\"]',0,'2026-05-14 23:42:41','2026-05-14 23:42:41'),('73e431f0-4fd5-11f1-9abe-6c02e0d26821','dde5cde4-4fcc-11f1-9abe-6c02e0d26821',NULL,NULL,'454cde6d-4f80-11f1-ba5b-00090ffe0001','multiple_choice','Which method starts listening for incoming connections in an Express app?','[\"app.listen()\", \"app.start()\", \"app.run()\", \"http.startServer()\"]',0,'2026-05-14 23:42:41','2026-05-14 23:42:41'),('73e4854d-4fd5-11f1-9abe-6c02e0d26821','dde5cde4-4fcc-11f1-9abe-6c02e0d26821',NULL,NULL,'454cde6d-4f80-11f1-ba5b-00090ffe0001','written','Briefly describe req and res in Express.','[\"req is the incoming request object (headers, body, params); res is the response object used to send data back to the client (res.send, res.json, res.status).\"]',0,'2026-05-14 23:42:41','2026-05-14 23:42:41'),('73e5283a-4fd5-11f1-9abe-6c02e0d26821','dde5cde4-4fcc-11f1-9abe-6c02e0d26821',NULL,NULL,'454cde6d-4f80-11f1-ba5b-00090ffe0001','multiple_choice','How do you define a route that accepts a numeric id parameter?','[\"app.get(\'/items/:id\', handler)\", \"app.get(\'/items/id\', handler)\", \"app.get(\'/items/?id\', handler)\", \"app.get(\'/items/(id)\', handler)\"]',0,'2026-05-14 23:42:41','2026-05-14 23:42:41'),('73e58002-4fd5-11f1-9abe-6c02e0d26821','dde5cde4-4fcc-11f1-9abe-6c02e0d26821',NULL,NULL,'454cde6d-4f80-11f1-ba5b-00090ffe0001','true_false','Query parameters are accessed via req.params in Express.','[\"True\", \"False\"]',1,'2026-05-14 23:42:41','2026-05-14 23:42:41'),('73e6e2a4-4fd5-11f1-9abe-6c02e0d26821','dde5cde4-4fcc-11f1-9abe-6c02e0d26821',NULL,NULL,'454cde6d-4f80-11f1-ba5b-00090ffe0001','multiple_choice','What happens if a middleware neither calls next() nor sends a response?','[\"The request hangs and the client times out\", \"Express calls next() automatically\", \"An error is thrown immediately\", \"The response is sent with status 204\"]',0,'2026-05-14 23:42:41','2026-05-14 23:42:41'),('73e72ec8-4fd5-11f1-9abe-6c02e0d26821','dde5cde4-4fcc-11f1-9abe-6c02e0d26821',NULL,NULL,'454cde6d-4f80-11f1-ba5b-00090ffe0001','written','Give an example use-case for middleware in Express.','[\"Examples include logging, authentication checks, parsing request bodies, input validation, and error handling middleware.\"]',0,'2026-05-14 23:42:41','2026-05-14 23:42:41'),('73e8033c-4fd5-11f1-9abe-6c02e0d26821','dde5cde4-4fcc-11f1-9abe-6c02e0d26821',NULL,NULL,'454cde6d-4f80-11f1-ba5b-00090ffe0001','multiple_choice','What is the signature of an Express error-handling middleware?','[\"(err, req, res, next)\", \"(req, res, next, err)\", \"(req, res)\", \"(err, next)\"]',0,'2026-05-14 23:42:41','2026-05-14 23:42:41'),('73e84f61-4fd5-11f1-9abe-6c02e0d26821','dde5cde4-4fcc-11f1-9abe-6c02e0d26821',NULL,NULL,'454cde6d-4f80-11f1-ba5b-00090ffe0001','true_false','An error-handling middleware must be added after other middleware and routes to catch their errors.','[\"True\", \"False\"]',0,'2026-05-14 23:42:41','2026-05-14 23:42:41'),('73e96d53-4fd5-11f1-9abe-6c02e0d26821','dde5cde4-4fcc-11f1-9abe-6c02e0d26821',NULL,NULL,'454cde6d-4f80-11f1-ba5b-00090ffe0001','multiple_choice','Which middleware parses incoming JSON payloads?','[\"express.json()\", \"express.body()\", \"bodyParser.text()\", \"express.urlencoded()\"]',0,'2026-05-14 23:42:41','2026-05-14 23:42:41'),('73ea56cf-4fd5-11f1-9abe-6c02e0d26821','dde5cde4-4fcc-11f1-9abe-6c02e0d26821',NULL,NULL,'454cde6d-4f80-11f1-ba5b-00090ffe0001','true_false','You should enable body parsing middleware before defining routes that need access to req.body.','[\"True\", \"False\"]',0,'2026-05-14 23:42:41','2026-05-14 23:42:41'),('73eb005a-4fd5-11f1-9abe-6c02e0d26821','dde5cde4-4fcc-11f1-9abe-6c02e0d26821',NULL,NULL,'454cde6d-4f80-11f1-ba5b-00090ffe0001','multiple_choice','Which Mongoose method saves a document instance to the database?'