INSERT INTO `job_posting` VALUES ('66835c7b-542d-11f1-9abe-6c02e0d26821','Hiring C++ Instructor','We are looking for a C++ Instructor to join our online learning platform.','Strong knowledge of C++ programming\nAbility to explain programming concepts clearly\nExperience in teaching or creating programming content\nAbility to create practical examples and exercises\nGood communication skills','Record and prepare C++ course lessons\nCreate assignments, quizzes, and projects\nSupport students and answer questions\nDevelop beginner-friendly educational content',NULL,'open','ba9e888a-18fc-11f1-97b2-6c02e0d26821','2026-05-20 12:22:19','2026-05-20 12:50:46'),('e29ccac0-5433-11f1-9abe-6c02e0d26821','Java Programming Instructor','We are looking for a skilled Java Instructor to join our online education platform and help students learn Java programming from beginner to advanced levels.','Strong knowledge of Java programming\nAbility to explain concepts clearly\nExperience in teaching or software development\nGood communication skills','Create and record Java course content\nPrepare practical coding examples and projects\nDesign quizzes and assignments\nSupport students throughout the course',NULL,'closed','ba9e888a-18fc-11f1-97b2-6c02e0d26821','2026-05-20 13:08:44','2026-05-29 00:22:47');
