INSERT INTO `lesson_quiz_attempt_answer` VALUES ('04c01b44-c499-45a8-b39c-a3ceb53a45a8','8d2a171c-b7c0-4d7c-bdb4-ec645b531ea7','f45b3d59-56c9-11f1-ba5b-00090ffe0001','multiple_choice','Which of the following IDEs is NOT mentioned in the course as a Python IDE?','[\"VS Code\", \"PyCharm\", \"Jupyter\", \"Sublime Text\"]',3,NULL,3,1,'2026-05-23 20:21:09'),('09176a6c-2d28-4c92-b9d2-311b92bd37d7','8d2a171c-b7c0-4d7c-bdb4-ec645b531ea7','6a15eba9-56ca-11f1-ba5b-00090ffe0001','true_false','True or False: The course states that Python is an interpreted language.','[\"True\", \"False\"]',0,NULL,0,1,'2026-05-23 20:21:09'),('0c9aaeeb-ff52-4e83-98a0-1fae2fd0a79c','0567e602-58e8-448c-964a-0c286aa3fb66','6a1a94e5-56ca-11f1-ba5b-00090ffe0001','written','Write the exact Python statement that prints the following text to the console: Welcome to the Python course!','[\"print(\\\"Welcome to the Python course!\\\")\"]',NULL,'غغ',0,0,'2026-05-28 23:09:51'),('0eff474f-2050-44c8-9590-42cde09f7924','ed45211e-c166-45e7-8f96-ecc7c38b3fba','36d93e9d-56cd-11f1-ba5b-00090ffe0001','multiple_choice','Which terminal command will most directly show the installed Python version on your system?','[\"python --version\", \"python -version\", \"pip --version\", \"python --check\"]',0,NULL,0,1,'2026-05-23 20:33:57'),('1415ce9f-8963-4d91-981a-afbe50dade6d','5c63acbb-2be9-4af0-bc1b-6073963f9163','6a1a94e5-56ca-11f1-ba5b-00090ffe0001','written','Write the exact Python statement that prints the following text to the console: Welcome to the Python course!','[\"print(\\\"Welcome to the Python course!\\\")\"]',NULL,'ui',0,0,'2026-06-01 22:46:23'),('2f13d05d-faa5-4dc6-baa0-eaff2fc6ac18','8d2a171c-b7c0-4d7c-bdb4-ec645b531ea7','6a03e6be-56ca-11f1-ba5b-00090ffe0001','multiple_choice','Which of the following is a common field where Python is widely used (as stated in the course)?','[\"Web development\", \"Concrete mixing\", \"Hairdressing\", \"Automobile assembly line work\"]',0,NULL,0,1,'2026-05-23 20:21:09'),('327