INSERT INTO `module` VALUES ('1beb3952-5147-11f1-9abe-6c02e0d26821','3f364be3-5143-11f1-9abe-6c02e0d26821','Foundations of Databases & SQL','Introduce core database concepts, installation, and basic interactions with a relational DBMS.',1,'2026-05-16 19:48:47','2026-05-16 19:48:47'),('1befaa6b-5147-11f1-9abe-6c02e0d26821','3f364be3-5143-11f1-9abe-6c02e0d26821','Data Modeling and Schema Design','Teach entity-relationship modeling, normalization, and translating models into SQL schema.',2,'2026-05-16 19:48:47','2026-05-16 19:48:47'),('1bf2eec0-5147-11f1-9abe-6c02e0d26821','3f364be3-5143-11f1-9abe-6c02e0d26821','Querying Single Tables with SQL','Cover SELECT basics, filtering, sorting, expressions, and common functions on single-table queries.',3,'2026-05-16 19:48:47','2026-05-16 19:48:47'),('1bf75341-5147-11f1-9abe-6c02e0d26821','3f364be3-5143-11f1-9abe-6c02e0d26821','Aggregation, Grouping, and Advanced Aggregates','Teach grouping, HAVING, window functions, and advanced multi-level aggregation techniques.',4,'2026-05-16 19:48:47','2026-05-16 19:48:47'),('1bfa0ae5-5147-11f1-9abe-6c02e0d26821','3f364be3-5143-11f1-9abe-6c02e0d26821','Joins, Subqueries, and Set Operations','Explain how to combine data across tables using joins, subqueries, and set operators with performance considerations.',5,'2026-05-16 19:48:47','2026-05-16 19:48:47'),('1bfd52e9-5147-11f1-9abe-6c02e0d26821','3f364be3-5143-11f1-9abe-6c02e0d26821','Data Modification, Transactions, and Concurrency','Teach safe data modification, transactional control, isolation, locking, and upsert patterns.',6,'2026-05-16 19:48:47','2026-05-16 19:48:47'),('1bffe50a-5147-11f1-9abe-6c02e0d26821','3f364be3-5143-11f1-9abe-6c02e0d26821','Indexing, Performance Tuning, and Scaling','Focus on indexing strategies, query analysis, partitioning, and other performance-improving techniques.',7,'2026-05-16 19:48:47','2026-05-16 19:48:47'),('1c0259a6-5147-11f1-9abe-6c02e0d26821','3f364be3-5143-11f1-9abe-6c02e0d26821','Advanced SQL Features and Specialized Data Types','Cover JSON/JSONB, arrays, composite types, full-text search, and writing database-side functions.',8,'2026-05-16 19:48:47','2026-05-16 19:48:47'),('1c0561e7-5147-11f1-9abe-6c02e0d26821','3f364be3-5143-11f1-9abe-6c02e0d26821','Security, Operations, and Capstone Project','Teach security best practices, backup/replication, auditing, and apply everything in a practical capstone schema and query set.',9,'2026-05-16 19:48:47','2026-05-16 19:48:47'),('1f4967f9-4fbe-11f1-9abe-6c02e0d26821','d6476901-4fbb-11f1-9abe-6c02e0d26821','Introduction to Backend Development','This chapter explains what backend development is, how the internet works behind the scenes, and why Node.js became one of the most popular backend technologies.',1,'2026-05-14 20:55:41','2026-05-14 20:55:41'),('2b4f1c0b-4fc4-11f1-9abe-6c02e0d26821','d6476901-4fbb-11f1-9abe-6c02e0d26821','Node.js Fundamentals','In this chapter, students will master the core foundations of Node.js. They will learn about the CommonJS module system, how to create and export modules, and explore important built-in modules such as fs, path, os, and events. This chapter builds the essential skills needed to work effectively with Node.js before moving into more advanced topics.',2,'2026-05-14 21:38:58','2026-05-14 21:38:58'),('2f1e8078-5133-11f1-9abe-6c02e0d26821','ed1b33e8-5132-11f1-9abe-6c02e0d26821','TypeScript Essentials for the Web','Core TypeScript language features and compiler options applied to typical web development tasks.',1,'2026-05-16 17:26:10','2026-05-16 17:26:10'),('2f23c7bf-5133-11f1-9abe-6c02e0d26821','ed1b33e8-5132-11f1-9abe-6c02e0d26821','Tooling, Build, and Runtime Integration','Configure build tools, bundlers, and runtime integration to compile, lint, and ship TypeScript web applications.',2,'2026-05-16 17:26:10','2026-05-16 17:26:10'),('2f27500d-5133-11f1-9abe-6c02e0d26821','ed1b33e8-5132-11f1-9abe-6c02e0d26821','TypeScript with Modern Frontend Frameworks','Apply TypeScript patterns and best practices within popular frontend frameworks for building robust web UIs.',3,'2026-05-16 17:26:10','2026-05-16 17:26:10'),('2f2cd183-5133-11f1-9abe-6c02e0d26821','ed1b33e8-5132-11f1-9abe-6c02e0d26821','DOM, Browser APIs, and Client-side Data Handling','Use TypeScript to safely interact with DOM APIs, handle network data, and work with advanced browser features.',4,'2026-05-16 17:26:10','2026-05-16 17:26:10'),('2f30ad4f-5133-11f1-9abe-6c02e0d26821','ed1b33e8-5132-11f1-9abe-6c02e0d26821','Advanced Patterns, Testing, and Deployment for the Web','Advanced TypeScript type-system techniques, testing strategies, migration tactics, and optimizations for production web apps.',5,'2026-05-16 17:26:10','2026-05-16 17:26:10'),('328f0e15-4fc4-11f1-9abe-6c02e0d26821','d6476901-4fbb-11f1-9abe-6c02e0d26821','Asynchronous Programming in Node.js','This is one of the most important chapters in the course. It covers the non-blocking nature of Node.js and dives deep into asynchronous programming patterns. Students will learn callbacks, Promises, async/await syntax, error handling, and gain a solid understanding of the Event Loop ظـزظــظ¤ش┬ظ¤ش╪ش the heart of Node.js performance.',3,'2026-05-14 21:39:10','2026-05-14 21:39:10'),('3ae5fc6a-4fc4-11f1-9abe-6c02e0d26821','d6476901-4fbb-11f1-9abe-6c02e0d26821','Building Web Servers with Express.js','In this chapter, students will learn how to create web servers using Node.js. They will start with the built-in HTTP module, then move to Express.js ظـزظــظ¤ش┬ظ¤ش╪ش the most popular web framework for Node.js. Topics include routing, middleware, request and response objects, and serving static files.',4,'2026-05-14 21:39:24','2026-05-14 21:39:24'),('3c059e4e-5478-11f1-9abe-6c02e0d26821','5e6bb404-5476-11f1-9abe-6c02e0d26821','Fundamentals of C and Tooling','Covers what C is, how C programs are built and executed, and how to set up the tools needed to write and run code. This foundation ensures learners can create, compile, and debug simple programs on their own.',1,'2026-05-20 21:18:00','2026-05-20 21:18:00'),('3c1f5e4a-5478-11f1-9abe-6c02e0d26821','5e6bb404-5476-11f1-9abe-6c02e0d26821','Core C Syntax, Types, and Control Flow','Introduces C\'s core language features╪╕┬┬جtypes, operators, and control structures╪╕┬┬جso learners can write meaningful programs that store and manipulate data. Mastering these topics is essential for correct and predictable behavior.',2,'2026-05-20 21:18:00','2026-05-20 21:18:00'),('3c28c53d-5478-11f1-9abe-6c02e0d26821','5e6bb404-5476-11f1-9abe-6c02e0d26821','Functions, Pointers, Arrays, and Memory','Builds on core syntax to teach modular code, pointers, arrays/strings, and dynamic memory management, which are central to C programming. These concepts enable more flexible and efficient programs but require careful handling.',3,'2026-05-20 21:18:00','2026-05-20 21:18:00'),('3c317fc8-5478-11f1-9abe-6c02e0d26821','5e6bb404-5476-11f1-9abe-6c02e0d26821','File I/O, Data Structures, and Project Practices','Applies learned concepts to real-world tasks: file I/O, building command-line tools, implementing data structures, and applying testing and debugging workflows. This module prepares learners to build practical C programs.',4,'2026-05-20 21:18:00','2026-05-20 21:18:00'),('3e9eefdb-5522-11f1-9abe-6c02e0d26821','5de2c59c-551f-11f1-9abe-6c02e0d26821','Foundations of Algorithms in Python','Covers core algorithmic thinking, Big-O complexity, and the specific Python constructs used to write and reason about algorithms. This foundation ensures students can measure performance and write basic algorithmic code correctly.',1,'2026-05-21 17:34:59','2026-05-21 17:34:59'),('3ea8e225-5522-11f1-9abe-6c02e0d26821','5de2c59c-551f-11f1-9abe-6c02e0d26821','Linear Data Structures','Introduces sequence and linear data structures in Python╪╕┬┬جhow to implement and use lists, stacks, queues, and linked lists. Mastery here enables efficient data organization and direct application in algorithmic problems.',2,'2026-05-21 17:34:59','2026-05-21 17:34:59'),('3eb1ad1b-5522-11f1-9abe-6c02e0d26821','5de2c59c-551f-11f1-9abe-6c02e0d26821','Trees, Heaps, and Hashing','Covers non-linear structures: hash tables, heaps, binary trees, and binary search trees, focusing on Python implementations and performance trade-offs. These structures are essential for search, priority handling, and ordered data storage.',3,'2026-05-21 17:34:59','2026-05-21 17:34:59'),('3ec5d05d-5522-11f1-9abe-6c02e0d26821','5de2c59c-551f-11f1-9abe-6c02e0d26821','Graphs and Traversal Algorithms','Introduces graph representations and core algorithms: BFS, DFS, shortest paths, cycle detection, and topological sorting with Python implementations. Graph skills are critical for network, dependency, and path-finding problems.',4,'2026-05-21 17:34:59','2026-05-21 17:34:59'),('3ecc364e-5522-11f1-9abe-6c02e0d26821','5de2c59c-551f-11f1-9abe-6c02e0d26821','Algorithmic Problem Solving & Real-World Applications','Teaches common design patterns, advanced sorting, dynamic programming, and strategies for adapting algorithms to constraints and production environments. This module focuses on solving real algorithm problems and preparing solutions for interviews or production use.',5,'2026-05-21 17:34:59','2026-05-21 17:34:59'),('42dd539e-4fc4-11f1-9abe-6c02e0d26821','d6476901-4fbb-11f1-9abe-6c02e0d26821','Working with Databases','This chapter focuses on connecting Node.js applications to databases. Students will learn how to work with MongoDB using Mongoose (NoSQL) and get an introduction to SQL databases using PostgreSQL. They will also learn how to manage configuration securely using environment variables.',5,'2026-05-14 21:39:37','2026-05-14 21:39:37'),('494147be-4fc4-11f1-9abe-6c02e0d26821','d6476901-4fbb-11f1-9abe-6c02e0d26821','RESTful APIs and Advanced Express','Students will learn how to design and build clean, scalable RESTful APIs. This chapter covers proper HTTP methods and status codes, CRUD operations, route organization, controller structure, input validation using Joi or Zod, and best practices for structuring Express applications.',6,'2026-05-14 21:39:48','2026-05-14 21:39:48'),('512732ad-4fc4-11f1-9abe-6c02e0d26821','d6476901-4fbb-11f1-9abe-6c02e0d26821','Authentication and Authorization','Security is a critical part of any backend application. In this chapter, students will implement user registration, login, password hashing with bcrypt, and token-based authentication using JSON Web Tokens (JWT). They will also build protected routes using custom authentication middleware.',7,'2026-05-14 21:40:01','2026-05-14 21:40:01'),('5bd192c9-4fc4-11f1-9abe-6c02e0d26821','d6476901-4fbb-11f1-9abe-6c02e0d26821','Error Handling, Logging, and Testing','This chapter teaches how to make applications reliable and maintainable. Students will learn centralized error handling, custom error classes, structured logging with Winston or Pino, and how to write automated tests using Jest and Supertest for both unit and integration testing.',8,'2026-05-14 21:40:19','2026-05-14 21:40:19'),('5faffc1a-4fc4-11f1-9abe-6c02e0d26821','d6476901-4fbb-11f1-9abe-6c02e0d26821','Security, Performance & Production','In the final chapter, students will prepare their applications for the real world. Topics include security best practices (Helmet, CORS, rate limiting), performance optimization, environment configuration, and deploying Node.js applications to platforms like Render, Railway, or Vercel.',9,'2026-05-14 21:40:26','2026-05-14 21:40:26'),('603620ee-20b0-11f1-97b2-6c02e0d26821','4f0dd6ed-2076-11f1-97b2-6c02e0d26821','Python Basics','-Python Syntax and Indentation\n-Variables and Data Types\n-Numbers and Mathematical Operations\n-Strings and String Manipulation\n-Comments and Code Readability\n-Input and Output in Python',2,'2026-03-15 22:48:52','2026-03-15 22:48:52'),('724c6c24-507c-11f1-9abe-6c02e0d26821','a2fe49a9-507b-11f1-9abe-6c02e0d26821','Module 1 ظـزظــظ¤ش┬ظ¤ش╪ش Java Setup and Basic Syntax','Introduce the Java platform, install tools, and learn the fundamental syntax needed to write and run simple Java programs.',1,'2026-05-15 19:38:04','2026-05-15 19:38:04'),('7252ac5d-507c-11f1-9abe-6c02e0d26821','a2fe49a9-507b-11f1-9abe-6c02e0d26821','Module 2 ظـزظــظ¤ش┬ظ¤ش╪ش Core Language Constructs','Cover Java operators, control flow, methods, arrays, and String handling to build non-trivial single-class programs.',2,'2026-05-15 19:38:04','2026-05-15 19:38:04'),('72561198-507c-11f1-9abe-6c02e0d26821','a2fe49a9-507b-11f1-9abe-6c02e0d26821','Module 3 ظـزظــظ¤ش┬ظ¤ش╪ش Object-Oriented Programming in Java','Teach Java\'s object-oriented features: classes and objects, encapsulation, inheritance, polymorphism, and interfaces to design modular programs.',3,'2026-05-15 19:38:04','2026-05-15 19:38:04'),('7259887e-507c-11f1-9abe-6c02e0d26821','a2fe49a9-507b-11f1-9abe-6c02e0d26821','Module 4 ظـزظــظ¤ش┬ظ¤ش╪ش Collections, Generics, Exceptions, and I/O','Introduce Java Collections, generics for type safety, exception handling patterns, and file I/O for persistent data access.',4,'2026-05-15 19:38:04','2026-05-15 19:38:04'),('725be7d4-507c-11f1-9abe-6c02e0d26821','a2fe49a9-507b-11f1-9abe-6c02e0d26821','Module 5 ظـزظــظ¤ش┬ظ¤ش╪ش Concurrency, Networking, Databases, and Tooling','Move to advanced practical skills: multithreading, networking, database access, and build/testing tools commonly used in Java projects.',5,'2026-05-15 19:38:04','2026-05-15 19:38:04'),('7c0ea9ec-2079-11f1-97b2-6c02e0d26821','4f0dd6ed-2076-11f1-97b2-6c02e0d26821','Introduction to Python','-What is Python?\n-History and Features of Python\n-Installing Python and Setting Up the Environment\n-Writing Your First Python Program\n-Understanding the Python Interpreter\n-Python IDEs (VS Code, PyCharm, Jupyter)',1,'2026-03-15 16:15:56','2026-03-15 21:55:53'),('95e8af72-5082-11f1-9abe-6c02e0d26821','4d9de360-5082-11f1-9abe-6c02e0d26821','Getting Started with CSS','Introduce CSS concepts, how to include styles in HTML, and fundamental syntax and selectors.',1,'2026-05-15 20:22:01','2026-05-15 20:22:01'),('95ee65d5-5082-11f1-9abe-6c02e0d26821','4d9de360-5082-11f1-9abe-6c02e0d26821','Box Model and Layout Basics','Cover the core box model, display types, positioning, floats, and measurement units that determine element layout.',2,'2026-05-15 20:22:01','2026-05-15 20:22:01'),('95f0f22e-5082-11f1-9abe-6c02e0d26821','4d9de360-5082-11f1-9abe-6c02e0d26821','Visual Styling: Color, Typography, and Backgrounds','Style text, colors, backgrounds, and images to create visually appealing interfaces and readable content.',3,'2026-05-15 20:22:01','2026-05-15 20:22:01'),('95f4152d-5082-11f1-9abe-6c02e0d26821','4d9de360-5082-11f1-9abe-6c02e0d26821','Modern Layouts and Responsive Design','Teach Flexbox, Grid, responsive strategies, and modern sizing functions to build adaptive layouts.',4,'2026-05-15 20:22:01','2026-05-15 20:22:01'),('95f75512-5082-11f1-9abe-6c02e0d26821','4d9de360-5082-11f1-9abe-6c02e0d26821','Interactivity, Optimization, and Best Practices','Add motion, variables, accessibility, performance optimizations, and maintainable workflows for production-ready CSS.',5,'2026-05-15 20:22:01','2026-05-15 20:22:01'),('bbc3623c-5132-11f1-9abe-6c02e0d26821','072aba94-5083-11f1-9abe-6c02e0d26821','Getting Started: JavaScript Fundamentals','Introduce core JavaScript concepts, syntax, and basic control structures to build a strong foundation.',1,'2026-05-16 17:22:56','2026-05-16 17:22:56'),('bbc8afc3-5132-11f1-9abe-6c02e0d26821','072aba94-5083-11f1-9abe-6c02e0d26821','Functions, Scope, and Error Handling','Cover function creation, scope management, modern function syntax, and techniques for handling and debugging errors.',2,'2026-05-16 17:22:56','2026-05-16 17:22:56'),('bbcc42ff-5132-11f1-9abe-6c02e0d26821','072aba94-5083-11f1-9abe-6c02e0d26821','Working with Objects and Arrays','Teach building and manipulating structured data with objects, arrays, JSON, and common functional helpers.',3,'2026-05-16 17:22:56','2026-05-16 17:22:56'),('bbd21409-5132-11f1-9abe-6c02e0d26821','072aba94-5083-11f1-9abe-6c02e0d26821','DOM, Events, and Browser APIs','Focus on interacting with web pages: selecting and modifying DOM elements, responding to events, and using browser storage.',4,'2026-05-16 17:22:56','2026-05-16 17:22:56'),('bbd5ee54-5132-11f1-9abe-6c02e0d26821','072aba94-5083-11f1-9abe-6c02e0d26821','Asynchronous JavaScript and Modern Workflow','Introduce asynchronous patterns, API interaction, ES modules, and basic project tooling for real-world JavaScript development.',5,'2026-05-16 17:22:56','2026-05-16 17:22:56'),('c51cc579-507d-11f1-9abe-6c02e0d26821','6c78daa9-507d-11f1-9abe-6c02e0d26821','Getting Started with HTML','Foundational concepts and the basic building blocks of an HTML document.',1,'2026-05-15 19:47:33','2026-05-15 19:47:33'),('c523bee3-507d-11f1-9abe-6c02e0d26821','6c78daa9-507d-11f1-9abe-6c02e0d26821','Semantic HTML and Document Structure','Use semantic elements and grouping to create meaningful, accessible page structure.',2,'2026-05-15 19:47:33','2026-05-15 19:47:33'),('c526ac8d-507d-11f1-9abe-6c02e0d26821','6c78daa9-507d-11f1-9abe-6c02e0d26821','Multimedia, Embedding, and Responsive Images','Embed and optimize media and external content for modern devices.',3,'2026-05-15 19:47:33','2026-05-15 19:47:33'),('c528e565-507d-11f1-9abe-6c02e0d26821','6c78daa9-507d-11f1-9abe-6c02e0d26821','Forms, Input Types, and Client-Side Validation','Build robust, accessible forms and leverage HTML features for input validation and UX.',4,'2026-05-15 19:47:33','2026-05-15 19:47:33'),('ced93aab-5066-11f1-9abe-6c02e0d26821','dde5cde4-4fcc-11f1-9abe-6c02e0d26821','Getting Started with Express','Set up an Express project, understand core concepts, and create basic, modular routes.',1,'2026-05-15 17:03:11','2026-05-15 17:03:11'),('cedd13cc-5066-11f1-9abe-6c02e0d26821','dde5cde4-4fcc-11f1-9abe-6c02e0d26821','Request Processing and Middleware','Learn to parse requests, validate input, handle files, and implement middleware patterns for cross-cutting concerns.',2,'2026-05-15 17:03:11','2026-05-15 17:03:11'),('cee1053e-5066-11f1-9abe-6c02e0d26821','dde5cde4-4fcc-11f1-9abe-6c02e0d26821','Building RESTful APIs with Databases','Design and implement RESTful endpoints integrated with a database, including patterns for modeling, queries, and transactions.',3,'2026-05-15 17:03:11','2026-05-15 17:03:11'),('cee246fd-5066-11f1-9abe-6c02e0d26821','dde5cde4-4fcc-11f1-9abe-6c02e0d26821','Security, Authentication, and Testing','Protect APIs, implement authentication and authorization, and verify behavior through automated tests.',4,'2026-05-15 17:03:11','2026-05-15 17:03:11');
